import { useState, useEffect, useRef } from 'react'
import { HashRouter as Router, Routes, Route, Link } from 'react-router-dom'
import { Activity, LayoutDashboard, Settings, Palette, Trophy, Compass } from 'lucide-react'
import './App.css'
import { getLocalNewsHeadlines } from './utils/telemetry'

// Placeholder components
import Dashboard from './pages/Dashboard'
import StockDetails from './pages/StockDetails'
import ETFAwards from './pages/ETFAwards'
import Discovery from './pages/Discovery'

const SECTORS = [
  { id: 'basicmaterials', label: 'Basic Materials' },
  { id: 'communicationservices', label: 'Communication Services' },
  { id: 'consumercyclical', label: 'Consumer Cyclical' },
  { id: 'consumerdefensive', label: 'Consumer Defensive' },
  { id: 'energy', label: 'Energy' },
  { id: 'financial', label: 'Financial' },
  { id: 'healthcare', label: 'Healthcare' },
  { id: 'industrials', label: 'Industrials' },
  { id: 'realestate', label: 'Real Estate' },
  { id: 'technology', label: 'Technology' },
  { id: 'utilities', label: 'Utilities' },
];

const SettingsPage = ({ excludedSectors, setExcludedSectors, autoRefreshInterval, setAutoRefreshInterval }) => {
  const toggleSector = (id) => {
    if (excludedSectors.includes(id)) {
      setExcludedSectors(excludedSectors.filter(s => s !== id));
    } else {
      setExcludedSectors([...excludedSectors, id]);
    }
  };

  return (
    <div className="settings" style={{ maxWidth: '600px', margin: '0 auto' }}>
      <h2>Scanner Settings</h2>
      <p className="text-muted" style={{ marginBottom: '2rem' }}>Configure your stock screener preferences and ignored sectors.</p>

      <div className="glass-panel" style={{ padding: '2rem' }}>
        <h3 style={{ marginTop: 0, marginBottom: '1rem' }}>Omitted Sectors</h3>
        <p className="text-muted" style={{ fontSize: '0.9rem', marginBottom: '1.5rem' }}>
          Check any sectors below to completely exclude them from your "Any Sector" broad market searches.
        </p>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
          {SECTORS.map(sector => (
            <label key={sector.id} className="flex-center" style={{ justifyContent: 'flex-start', gap: '0.5rem', cursor: 'pointer' }}>
              <input
                type="checkbox"
                checked={excludedSectors.includes(sector.id)}
                onChange={() => toggleSector(sector.id)}
                style={{
                  accentColor: 'var(--primary)',
                  width: '16px',
                  height: '16px',
                  cursor: 'pointer'
                }}
              />
              <span style={{ color: excludedSectors.includes(sector.id) ? 'var(--danger)' : 'var(--text-main)' }}>
                {sector.label}
              </span>
            </label>
          ))}
        </div>
      </div>

      <div className="glass-panel" style={{ padding: '2rem', marginTop: '2rem' }}>
        <h3 style={{ marginTop: 0, marginBottom: '1rem' }}>Auto-Refresh Interval</h3>
        <p className="text-muted" style={{ fontSize: '0.9rem', marginBottom: '1.5rem' }}>
          Automatically refresh the dashboard stock ticker data every set number of minutes.
        </p>

        <select
          value={autoRefreshInterval}
          onChange={(e) => setAutoRefreshInterval(Number(e.target.value))}
          style={{
            padding: '0.75rem',
            background: 'rgba(0,0,0,0.3)',
            border: '1px solid rgba(255,255,255,0.2)',
            color: 'var(--text-main)',
            borderRadius: '6px',
            fontFamily: 'inherit',
            outline: 'none',
            cursor: 'pointer'
          }}
        >
          <option value={0}>Off (Manual Only)</option>
          <option value={1}>Every 1 Minute</option>
          <option value={15}>Every 15 Minutes</option>
          <option value={30}>Every 30 Minutes</option>
        </select>
      </div>
    </div>
  )
}

function App() {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('dipAnalyzerTheme');
    if (saved === 'theme-seizure') return 'theme-majestic';
    return saved || 'theme-majestic';
  });

  const previousThemeRef = useRef('theme-majestic');

  const [excludedSectors, setExcludedSectors] = useState(() => {
    const saved = localStorage.getItem('excludedSectors');
    return saved ? JSON.parse(saved) : [];
  });
  const [autoRefreshInterval, setAutoRefreshInterval] = useState(() => {
    const saved = localStorage.getItem('autoRefreshInterval');
    return saved ? JSON.parse(saved) : 0;
  });

  useEffect(() => {
    document.body.className = theme;
    // Don't persist seizure mode so it doesn't terrify someone on next startup
    if (theme !== 'theme-seizure') {
      localStorage.setItem('dipAnalyzerTheme', theme);
      previousThemeRef.current = theme;
    }
  }, [theme]);

  // 20 Second Reversion for Seizure Mode
  useEffect(() => {
    if (theme === 'theme-seizure') {
      const timer = setTimeout(() => {
        setTheme(previousThemeRef.current || 'theme-majestic');
      }, 20000);
      return () => clearTimeout(timer);
    }
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('excludedSectors', JSON.stringify(excludedSectors));
  }, [excludedSectors]);

  useEffect(() => {
    localStorage.setItem('autoRefreshInterval', JSON.stringify(autoRefreshInterval));
  }, [autoRefreshInterval]);

  // Cryptic Telemetry (Local News logic)
  const [telemetryData, setTelemetryData] = useState([]);
  const [currentLine, setCurrentLine] = useState(0);

  useEffect(() => {
    let intervalId;
    if (theme === 'theme-seizure') {
      getLocalNewsHeadlines().then(lines => {
        setTelemetryData(lines);
        setCurrentLine(0);
        // Swap out the chaotic text aggressively
        intervalId = setInterval(() => {
          setCurrentLine(prev => (prev + 1) % lines.length);
        }, Math.random() * 2000 + 1000); // 1-3 seconds per headline
      });
    } else {
      setTelemetryData([]);
      setCurrentLine(0);
    }

    return () => clearInterval(intervalId);
  }, [theme]);

  return (
    <Router>
      <div className="app-container">

        {/* DOOMSDAY OVERLAY */}
        {theme === 'theme-seizure' && telemetryData.length > 0 && (
          <div className="telemetry-overlay">
            <h1 className="telemetry-text">
              {telemetryData[currentLine]}
            </h1>
          </div>
        )}

        <header className="flex-between glass-panel" style={{ padding: '1rem 2rem', marginBottom: '2rem' }}>
          <div className="logo flex-center" style={{ gap: '0.5rem' }}>
            <Activity color="var(--primary)" />
            <span className="text-gradient" style={{ fontFamily: 'var(--font-heading)', fontWeight: '700', fontSize: '1.2rem' }}>
              DipAnalyzer Pro
            </span>
          </div>
          <nav style={{ display: 'flex', gap: '1.5rem', alignItems: 'center' }}>
            <div className="flex-center" style={{ gap: '0.5rem', color: 'var(--text-muted)', marginRight: '1rem' }}>
              <Palette size={16} />
              <select
                value={theme}
                onChange={(e) => setTheme(e.target.value)}
                style={{
                  background: 'transparent',
                  border: 'none',
                  color: 'var(--text-main)',
                  outline: 'none',
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                  fontSize: '0.9rem'
                }}
              >
                <option value="theme-majestic">Majestic</option>
                <option value="theme-trippy">Spacious / Trippy</option>
                <option value="theme-orange">Erotic Orange</option>
                <option value="theme-seizure">Seizure Mode</option>
              </select>
            </div>
            <Link to="/" className="flex-center" style={{ gap: '0.5rem', color: 'var(--text-main)' }}>
              <LayoutDashboard size={18} /> Dashboard
            </Link>
            <Link to="/etfs" className="flex-center" style={{ gap: '0.5rem', color: 'var(--text-main)' }}>
              <Trophy size={18} /> Daily ETFs
            </Link>
            <Link to="/discovery" className="flex-center" style={{ gap: '0.5rem', color: 'var(--text-main)' }}>
              <Compass size={18} /> Discovery
            </Link>
            <Link to="/settings" className="flex-center" style={{ gap: '0.5rem', color: 'var(--text-muted)' }}>
              <Settings size={18} /> Settings
            </Link>
          </nav>
        </header>

        <main>
          <Routes>
            <Route path="/" element={<Dashboard excludedSectors={excludedSectors} autoRefreshInterval={autoRefreshInterval} />} />
            <Route path="/stock/:symbol" element={<StockDetails />} />
            <Route path="/etfs" element={<ETFAwards excludedSectors={excludedSectors} autoRefreshInterval={autoRefreshInterval} />} />
            <Route path="/discovery" element={<Discovery excludedSectors={excludedSectors} autoRefreshInterval={autoRefreshInterval} />} />
            <Route path="/settings" element={<SettingsPage excludedSectors={excludedSectors} setExcludedSectors={setExcludedSectors} autoRefreshInterval={autoRefreshInterval} setAutoRefreshInterval={setAutoRefreshInterval} />} />
          </Routes>
        </main>
      </div>
    </Router>
  )
}

export default App

import { useState } from 'react';
import { TrendingUp, TrendingDown, Clock, Activity } from 'lucide-react';
import { Link } from 'react-router-dom';

const StockCard = ({ symbol, name, price, dipPercentage, recoveryProbability, isZombie }) => {
    let scoreColor = 'var(--text-muted)';
    let scoreText = 'Neutral Signal';
    let scoreClass = '';

    if (isZombie) {
        scoreColor = '#666';
        scoreText = 'ZOMBIE / DEAD';
        scoreClass = '';
    } else if (recoveryProbability >= 70) {
        scoreColor = 'var(--success)';
        scoreText = 'Strong Buy Signal';
        scoreClass = 'rating-pulse-success';
    } else if (recoveryProbability >= 40) {
        scoreColor = 'var(--warning)';
        scoreText = 'Hold / Watch';
        scoreClass = 'rating-pulse-warning';
    } else {
        scoreColor = 'var(--danger)';
        scoreText = 'Weak Bounce Chance';
        scoreClass = 'rating-pulse-danger';
    }

    return (
        <Link to={`/stock/${symbol}`} className="glass-panel" style={{
            display: 'block',
            padding: '1.5rem',
            textDecoration: 'none',
            color: 'inherit',
            transition: 'transform 0.2s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.2s',
            opacity: isZombie ? 0.6 : 1,
            filter: isZombie ? 'grayscale(100%)' : 'none'
        }}
            onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.boxShadow = '0 12px 40px rgba(0, 242, 254, 0.15)';
            }}
            onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'var(--glass-shadow)';
            }}>
            <div className="flex-between" style={{ marginBottom: '1rem' }}>
                <div>
                    <h3 style={{ margin: 0, fontSize: '1.25rem', color: 'var(--text-main)' }}>{symbol}</h3>
                    <span className="text-muted" style={{ fontSize: '0.85rem' }}>{name}</span>
                </div>
                <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: '1.2rem', fontWeight: '600' }}>${price.toFixed(2)}</div>
                    <div className="text-danger flex-center" style={{ gap: '0.25rem', fontSize: '0.9rem', justifyContent: 'flex-end' }}>
                        <TrendingDown size={14} />
                        {dipPercentage}%
                    </div>
                </div>
            </div>

            {/* Mini Chart Placeholder area */}
            <div style={{
                height: '60px',
                width: '100%',
                background: 'rgba(255,255,255,0.02)',
                borderRadius: '8px',
                marginBottom: '1rem',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'var(--text-muted)'
            }}>
                <Activity size={20} style={{ opacity: 0.5 }} />
            </div>

            <div className="flex-between" style={{ fontSize: '0.85rem', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '1rem' }}>
                <div className="flex-center" style={{ gap: '0.3rem', color: 'var(--text-muted)' }}>
                    <Clock size={14} /> Since Peak
                </div>
                <div className="flex-center" style={{ gap: '0.4rem' }}>
                    <div className={scoreClass} style={{
                        width: '8px',
                        height: '8px',
                        borderRadius: '50%',
                        backgroundColor: scoreColor,
                        boxShadow: `0 0 8px ${scoreColor}`
                    }} />
                    <span style={{ color: scoreColor }}>
                        {scoreText} ({recoveryProbability})
                    </span>
                </div>
            </div>
        </Link>
    );
};

export default StockCard;

import { useState, useEffect } from 'react';
import { Search, SlidersHorizontal, RefreshCw } from 'lucide-react';
import StockCard from '../components/StockCard';

const Dashboard = ({ excludedSectors = [], autoRefreshInterval = 0 }) => {
    const [chartCount, setChartCount] = useState(20);
    const [searchTerm, setSearchTerm] = useState('');
    const [sector, setSector] = useState(''); // Empty string means "Any Sector"
    const [stocks, setStocks] = useState([]);
    const [loading, setLoading] = useState(true);

    const calculateRecoveryScore = async (symbol, electron) => {
        if (!electron) {
            // Mock score if running outside Electron
            return Math.floor(Math.random() * 80) + 10;
        }

        try {
            const yahooData = await electron.ipcRenderer.invoke('fetch-yahoo-chart', symbol);
            const result = yahooData?.chart?.result?.[0];
            if (!result) return 50;

            const timestamps = result.timestamp;
            const closes = result.indicators.quote[0].close;
            const chartData = timestamps.map((ts, index) => ({
                price: closes[index]
            })).filter(d => d.price !== null);

            if (chartData.length === 0) return 50;

            const currentPrice = chartData[chartData.length - 1].price;
            const peakPrice = Math.max(...chartData.map(d => d.price));
            const peakIndex = chartData.findIndex(d => d.price === peakPrice);
            const dipPercentage = peakPrice > 0 ? (((peakPrice - currentPrice) / peakPrice) * 100) : 0;

            let recoveryScore = 50;
            if (dipPercentage > 25) recoveryScore -= 20;
            else if (dipPercentage > 15) recoveryScore += 15;
            else if (dipPercentage > 5) recoveryScore += 25;
            else recoveryScore -= 10;

            if (chartData.length - peakIndex > 5) {
                const recentLow = Math.min(...chartData.slice(peakIndex).map(d => d.price));
                if (currentPrice > recentLow * 1.02) recoveryScore += 20;
                else recoveryScore -= 15;
            }

            return Math.max(0, Math.min(100, recoveryScore));
        } catch (e) {
            console.error(`Failed to calc score for ${symbol}`, e);
            return 50;
        }
    };

    const fetchFinvizData = async (targetCount) => {
        setLoading(true);
        try {
            let electron = null;
            if (typeof window !== 'undefined' && typeof window.require === 'function') {
                electron = window.require('electron');
            }

            let allStocks = [];

            if (!electron) {
                console.warn("Electron environment not detected. Loading mock dashboard data.");
                allStocks = [
                    { symbol: 'AAPL', name: 'Apple Inc.', price: 173.5, changePercentage: -2.4, dipPercentage: 2.4, recoveryProbability: 85, isZombie: false },
                    { symbol: 'TSLA', name: 'Tesla Inc.', price: 180.2, changePercentage: -5.1, dipPercentage: 5.1, recoveryProbability: 60, isZombie: false },
                    { symbol: 'DEAD', name: 'Zombie Corp', price: 0.5, changePercentage: -80.0, dipPercentage: 80.0, recoveryProbability: 10, isZombie: true },
                    { symbol: 'MSFT', name: 'Microsoft', price: 400.1, changePercentage: 1.2, dipPercentage: 0, recoveryProbability: 95, isZombie: false }
                ];
                setStocks(allStocks);
                setLoading(false);
                return;
            }

            let offset = 1;

            while (allStocks.length < targetCount) {
                // Construct Finviz filter: ind_stocksonly + custom sector filter if selected
                let filterStr = 'ind_stocksonly%2Cta_perf_1wup%2Cta_perf2_4wup%2Cta_sma20_pa%2Cta_sma200_sb50%2Cta_sma50_sb20';
                if (sector) {
                    filterStr += `%2Csec_${sector}`;
                }
                const url = `https://finviz.com/screener.ashx?v=111&p=d&f=${filterStr}&ta=0&dr=y1&o=-marketcap&r=${offset}`;
                const html = await electron.ipcRenderer.invoke('fetch-url', url);

                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');
                const rows = doc.querySelectorAll('tr');
                let pageStocks = [];

                rows.forEach(row => {
                    const cells = row.querySelectorAll('td');
                    if (cells.length >= 10) {
                        const numberText = cells[0].textContent.trim();
                        const tickerLink = cells[1].querySelector('a[href^="quote.ashx"]');

                        if (parseInt(numberText) > 0 && tickerLink) {
                            const ticker = tickerLink.textContent.trim();

                            // cells[3] on Finviz is the "Sector" column. Ex. "Technology" -> "technology"
                            const finvizSectorStr = cells[3]?.textContent.trim().toLowerCase().replace(/ /g, '') || '';
                            if (excludedSectors.includes(finvizSectorStr)) {
                                return; // Skip this stock entirely
                            }

                            const changeStr = cells[9].textContent.trim();
                            const change = parseFloat(changeStr.replace('%', '')) || 0;

                            // Prevent duplicates
                            if (ticker && !allStocks.find(s => s.symbol === ticker) && !pageStocks.find(s => s.symbol === ticker)) {
                                pageStocks.push({
                                    symbol: ticker,
                                    name: cells[2].textContent.trim(),
                                    price: parseFloat(cells[8].textContent.trim()) || 0,
                                    changePercentage: change,
                                    dipPercentage: change < 0 ? Math.abs(change) : 0,
                                    recoveryProbability: 50, // Default, will get updated asynchronously
                                    isZombie: false
                                });
                            }
                        }
                    }
                });

                if (pageStocks.length === 0) break; // no more pages

                // Asynchronously hydrate scores for this page to speed up visible load
                Promise.all(pageStocks.map(async (stock) => {
                    const score = await calculateRecoveryScore(stock.symbol, electron);
                    setStocks((prev) => prev.map(s => s.symbol === stock.symbol ? {
                        ...s,
                        recoveryProbability: score,
                        isZombie: score < 20 // Zombie heuristic
                    } : s));
                }));

                allStocks = [...allStocks, ...pageStocks];
                setStocks(allStocks); // Update UI incrementally

                offset += 20; // Finviz pagination is by 20 objects

                // Be polite to the scraper endpoint slightly
                await new Promise(res => setTimeout(res, 500));
            }
        } catch (error) {
            console.error("Failed to fetch Finviz", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchFinvizData(chartCount);
    }, [chartCount, sector, excludedSectors]);

    useEffect(() => {
        if (autoRefreshInterval <= 0) return;

        const intervalId = setInterval(() => {
            fetchFinvizData(chartCount);
        }, autoRefreshInterval * 60 * 1000);

        return () => clearInterval(intervalId);
    }, [autoRefreshInterval, chartCount, sector, excludedSectors]);

    const filteredStocks = stocks.filter(s => s.symbol.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="dashboard">
            {/* Header Area */}
            <div className="flex-between" style={{ marginBottom: '2rem' }}>
                <div>
                    <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        Market Dips Analysis
                        {loading && <RefreshCw size={20} className="text-muted" style={{ animation: 'spin 1s linear infinite' }} />}
                    </h2>
                    <p className="text-muted">Analyzing oversold opportunities based on your Finviz screener.</p>
                </div>

                <div className="flex-center" style={{ gap: '1rem' }}>
                    <div className="glass-panel flex-center" style={{ padding: '0.5rem 1rem', gap: '0.5rem', borderRadius: '30px' }}>
                        <Search size={18} color="var(--text-muted)" />
                        <input
                            type="text"
                            placeholder="Search ticker..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            style={{
                                background: 'transparent',
                                border: 'none',
                                color: 'var(--text-main)',
                                outline: 'none',
                                width: '150px',
                                fontFamily: 'inherit'
                            }}
                        />
                    </div>

                    <div className="glass-panel flex-center" style={{ padding: '0.5rem 1rem', gap: '0.5rem', borderRadius: '30px' }}>
                        <SlidersHorizontal size={18} color="var(--text-muted)" />

                        {/* Sector Filter Dropdown */}
                        <select
                            value={sector}
                            onChange={(e) => setSector(e.target.value)}
                            style={{
                                background: 'transparent',
                                border: 'none',
                                color: 'var(--text-main)',
                                outline: 'none',
                                cursor: 'pointer',
                                fontFamily: 'inherit',
                                borderRight: '1px solid rgba(255,255,255,0.1)',
                                paddingRight: '0.5rem',
                                marginRight: '0.5rem'
                            }}
                        >
                            <option value="">Any Sector</option>
                            <option value="basicmaterials">Basic Materials</option>
                            <option value="communicationservices">Communication Services</option>
                            <option value="consumercyclical">Consumer Cyclical</option>
                            <option value="consumerdefensive">Consumer Defensive</option>
                            <option value="energy">Energy</option>
                            <option value="financial">Financial</option>
                            <option value="healthcare">Healthcare</option>
                            <option value="industrials">Industrials</option>
                            <option value="realestate">Real Estate</option>
                            <option value="technology">Technology</option>
                            <option value="utilities">Utilities</option>
                        </select>

                        <select
                            value={chartCount}
                            onChange={(e) => setChartCount(Number(e.target.value))}
                            style={{
                                background: 'transparent',
                                border: 'none',
                                color: 'var(--text-main)',
                                outline: 'none',
                                cursor: 'pointer',
                                fontFamily: 'inherit'
                            }}
                        >
                            <option value={10}>Top 10 Dips</option>
                            <option value={20}>Top 20 Dips</option>
                            <option value={30}>Top 30 Dips</option>
                            <option value={50}>Top 50 Dips</option>
                        </select>
                    </div>
                </div>
            </div>

            {/* Stocks Grid */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
                gap: '1.5rem'
            }}>
                {filteredStocks.map((stock) => (
                    <StockCard key={stock.symbol} {...stock} />
                ))}

                {loading && Array.from({ length: Math.max(0, chartCount - stocks.length) }).map((_, i) => (
                    <div key={`loading-${i}`} className="glass-panel" style={{
                        height: '210px',
                        opacity: 0.3,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        borderStyle: 'dashed'
                    }}>
                        <span className="text-muted">Scanning Finviz #{stocks.length + i + 1}...</span>
                    </div>
                ))}

                {!loading && filteredStocks.length === 0 && (
                    <div className="text-muted">No stocks found matching your criteria.</div>
                )}
            </div>
            {/* Adding this style locally for the spinner */}
            <style>{`
                @keyframes spin { 100% { transform: rotate(360deg); } }
            `}</style>
        </div>
    );
};

export default Dashboard;
